#include <bits/stdc++.h> 
using namespace std;

const int MOD = 1e9 + 7;  // To handle large numbers
vector<int> dp;

int countWaysDP(int n) {
    // Base cases
    if(n <= 1) return 1;
    if(dp[n] != -1) return dp[n];

    // Calculate ways using recursion with memoization
    return dp[n] = (countWaysDP(n-1) + countWaysDP(n-2)) % MOD;
}

int main() {
    int T;
    cin >> T;

    while(T--) {
        int N;
        cin >> N;
        dp.assign(N + 1, -1);  // Reset dp array for each test case
        cout << countWaysDP(N) << endl;
    }
    return 0;
}
